Here's a simplified Goose recipe you could use:

{
  "name": "add-podcast-episode",
  "description": "Automates adding a new podcast episode to Nuxt content site",
  "parameters": {
    "type": "object",
    "properties": {
      "podcastUrl": {
        "type": "string",
        "description": "URL of the podcast episode page"
      }
    },
    "required": ["podcastUrl"]
  },
  "steps": [
    {
      "name": "Extract podcast data",
      "action": "playwright.mcp",
      "args": {
        "action": "navigate",
        "url": "{{podcastUrl}}"
      }
    },
    {
      "name": "Create markdown file",
      "action": "fs.writeFile",
      "args": {
        "path": "content/podcasts/{{podcastTitle}}.md",
        "content": "---\ntitle: {{podcastTitle}}\ndate: {{podcastDate}}\nhost: {{podcastHost}}\npodcastUrl: {{podcastUrl}}\nimage: {{imageUrl}}\n---"
      }
    },
    {
      "name": "Upload image to Cloudinary",
      "action": "cloudinary.mcp.upload",
      "args": {
        "path": "local/podcast-{{podcastTitle}}.jpg",
        "folder": "podcasts"
      }
    },
    {
      "name": "Verify in dev server",
      "action": "playwright.mcp",
      "args": {
        "action": "navigate",
        "url": "http://localhost:3000/podcasts"
      }
    },
    {
      "name": "Create PR",
      "action": "github.mcp.createPr",
      "args": {
        "title": "Add {{podcastTitle}} episode",
        "branch": "add/{{podcastTitle}}"
      }
    }
  ]
}
